const body = $json.body ?? {};
const errors = [];

if (!body.name) errors.push('name');
if (!body.email) errors.push('email');
if (body.consent !== 'granted') errors.push('consent');

if (errors.length) {
  return [
    {
      json: {
        valid: false,
        statusCode: 400,
        responseBodyJson: JSON.stringify({
          ok: false,
          error: `Campos obrigatórios ausentes ou inválidos: ${errors.join(', ')}`
        })
      }
    }
  ];
}

return [
  {
    json: {
      valid: true,
      body
    }
  }
];

function sqlText(value) {
  if (value === undefined || value === null || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlJson(value, fallback = {}) {
  const safeValue = value === undefined || value === null ? fallback : value;
  return `'${JSON.stringify(safeValue).replace(/'/g, "''")}'::jsonb`;
}

function sqlTimestamp(value) {
  if (!value) return 'now()';
  return `${sqlText(value)}::timestamptz`;
}

if (!$json.valid) {
  return [
    {
      json: {
        query: `select ${$json.statusCode} as status_code, ${sqlText($json.responseBodyJson)}::json as response_body;`
      }
    }
  ];
}

const body = $json.body;
const stage = Array.isArray(body.stage) ? body.stage : body.stage ? [body.stage] : [];

const query = `
with inserted as (
  insert into site_leads (
    created_at,
    form_type,
    page,
    title,
    interest,
    offer,
    name,
    email,
    phone,
    stage,
    consent,
    consent_timestamp,
    legal_notice_version,
    tracking_json,
    raw_payload_json
  ) values (
    ${sqlTimestamp(body.createdAt)},
    ${sqlText(body.formType)},
    ${sqlText(body.page)},
    ${sqlText(body.title)},
    ${sqlText(body.interest)},
    ${sqlText(body.offer)},
    ${sqlText(body.name)},
    ${sqlText(body.email)},
    ${sqlText(body.phone)},
    ${sqlJson(stage, [])},
    ${sqlText(body.consent)},
    ${sqlTimestamp(body.consentTimestamp)},
    ${sqlText(body.legalNoticeVersion)},
    ${sqlJson(body.tracking)},
    ${sqlJson(body)}
  )
  returning id
)
select 200 as status_code, '{"ok":true}'::json as response_body from inserted;
`;

return [{ json: { query } }];
